"""Batch translations 151-275 for Distinction III."""

BATCH: dict[int, dict] = {
151: {"nativeDefinition": "In a very remote, isolated area.", "japaneseMeaning": "ど真ん中のどこにもない場所", "etymology": "middle of nowhere（どこでもない真ん中）が人里離れた場所を表す。", "examples": {"B": "どこにもない場所に住んでるけど、NYのアパートより広さがあってずっと幸せ。", "C": "酔い潰れてどこにもない場所にたどり着いた。ここがどこか全然わからない。", "D": "非常に辺鄙な場所に。"}},
152: {"nativeDefinition": "Continuously, every day without change.", "japaneseMeaning": "毎日欠かさず、日々", "etymology": "day in, day out（日々）が毎日繰り返されることを表す。", "examples": {"B": "多くの賢い人は大器晩成型。例えばこの科学者は日々努力を重ね、97歳でノーベル賞を受賞した。", "C": "日々働いてれば、早期退職も夢じゃない。", "D": "絶えず。"}},
153: {"nativeDefinition": "A narrow escape from danger or failure.", "japaneseMeaning": "危ないところだった、ギリギリセーフ", "etymology": "close call（接近した呼び出し）が危機一髪を表す。", "examples": {"B": "電車との危ないところだった。まだビクビクしてる。", "C": "危ないところだった！飛行機乗り遅れるところだった。", "D": "危険からのギリギリの脱出。"}},
154: {"nativeDefinition": "Excessive; more than necessary.", "japaneseMeaning": "やりすぎ、過剰", "etymology": "overkill（殺しすぎ）が必要以上のことを表す。", "examples": {"B": "バーガーは美味しかったけど、パティ4枚はやりすぎ。誰がこれ食べ切れる？", "C": "彼女のメイク量はやりすぎ。整形したみたいに見える。", "D": "過剰。"}},
155: {"nativeDefinition": "A minor problem or temporary setback.", "japaneseMeaning": "小さなトラブル、つまずき", "etymology": "hiccup（しゃっくり）が小さな障害の比喩。", "examples": {"B": "フォロワー1000人まであと少し。今月末には達するはず、小さなトラブルがなければ。", "C": "すでに遅れてるから、これ以上トラブルは許されない。マイクをプロジェクトに入れて安定させよう。", "D": "小さな問題や挫折。"}},
156: {"nativeDefinition": "To be better than something.", "japaneseMeaning": "（〜に）勝る、〜より優れている", "etymology": "beat（打ち負かす）が比喩的に「〜より優れる」を表す。", "examples": {"B": "ヨーロッパ一人旅に戻ると、一人旅は誰かと一緒より断然いい。ルートを自分で選べるから。", "C": "エベレスト頂上は人生で最も難しかった。でもあの達成感に勝るものはない。", "D": "何かより優れている。"}},
157: {"nativeDefinition": "Expressing regret about a past foolish decision.", "japaneseMeaning": "何考えてたんだろう", "etymology": "I don't know what I was thinking（何を考えてたかわからない）が後悔を表す。", "examples": {"B": "何考えてたんだろう。このスタートアップに全ツッパしたけど、今考えると誰がこのアプリ欲しがる？", "C": "来週スカイダイビングに申し込んじゃった。何考えてたんだろう。飛行機から飛び降りるよりバカなことない。", "D": "後悔している。"}},
158: {"nativeDefinition": "The advantages and disadvantages of something.", "japaneseMeaning": "長所と短所、メリット・デメリット", "etymology": "pros and cons（賛成と反対）が両面の評価を表す。", "examples": {"B": "誰にだって長所と短所がある。完璧なパートナーを探すのは時間の無駄。", "C": "Amazonにも長所短所あるのはわかってるけど、Eコマースの先駆者だと信じてる。", "D": "長所と短所。"}},
159: {"nativeDefinition": "A day or period that is completely unproductive.", "japaneseMeaning": "ダメな一日、潰れた日", "etymology": "write-off（帳消し）が失われた時間を表す。", "examples": {"B": "今日は完全に潰れた日。午前中ずっと会議で、午後はネット止まった。もう帰ろう。", "C": "今夜トビーと飲んでショットやるから、明日は潰れた日になりそう。", "D": "非生産的な時間。"}},
160: {"nativeDefinition": "A hidden drawback or trick.", "japaneseMeaning": "落とし穴、条件", "etymology": "catch（捕まえる）が隠れた問題を指す。", "examples": {"B": "この美品マップが50ドル？良すぎて怪しい。どこかに落とし穴があるはず。", "C": "誰かがすごく親切にしてくれたら、いつも落とし穴があると思う。", "D": "トリック。"}},
161: {"nativeDefinition": "Something unfortunate that just happens sometimes.", "japaneseMeaning": "そういうものだ、仕方ない", "etymology": "just one of those things（そういうことの一つ）が仕方ない出来事を表す。", "examples": {"B": "美容師に少しだけトップを切ってって言ったのに、また丸刈りにされた。そういうものかな。", "C": "クリーニング取りに行かなきゃ。面倒だけど、そういうものだ。", "D": "こういうことは起こる。"}},
162: {"nativeDefinition": "Unwilling to change one's habits or opinions.", "japaneseMeaning": "古い考えに固執している", "etymology": "stuck in one's ways（自分のやり方に固まっている）が変化を拒むことを表す。", "examples": {"B": "多くの日本企業はまだ古いやり方に固執してる。紙や印鑑をまだ使ってる。", "C": "父は古い考えに固執してる。Google Maps使わず紙の地図。老いぼれは新しい芸ができない。", "D": "習慣や考えを変える気がない。"}},
163: {"nativeDefinition": "To be verified as true or consistent.", "japaneseMeaning": "（話などが）筋が通る、確認できる", "etymology": "check out（確認する）が事実と一致することを表す。", "examples": {"B": "え、何？話が筋通ってないよ。昨夜家で勉強してたのに、今朝ひどい二日酔い？飲んでたの？勉強してたの？", "C": "前に言ったこと、筋が通ってる。ここでは米が魚より高くなってる。寿司に米がほとんどない、変だ。", "D": "理にかなう。"}},
164: {"nativeDefinition": "To make a critical or sarcastic remark about someone.", "japaneseMeaning": "（人を）皮肉る、嫌味を言う", "etymology": "dig at（突く）が嫌味を言うことを表す。", "examples": {"B": "君を皮肉ったわけじゃない。そのジャケット、誰が着てもバカみたいに見える。", "C": "たまに皮肉る人がいるけど、全然気にしない。集中するための雑音。", "D": "皮肉を言う。"}},
165: {"nativeDefinition": "Not aware of current trends or realities.", "japaneseMeaning": "時代遅れの、世間から取り残された", "etymology": "out of touch（触れ合っていない）が現実から乖離していることを表す。", "examples": {"B": "コーヒー1杯10ドルが安いって？一般の人から取り残されてるよ。", "C": "政府は人々が本当に必要としてるものから取り残されてる。", "D": "最新の知識がない。"}},
166: {"nativeDefinition": "Refusing to accept an unpleasant truth.", "japaneseMeaning": "現実を認めない", "etymology": "in denial（否定中）が現実拒否の状態を表す。", "examples": {"B": "まだそのバカみたいな髪型を認めないの？学校で目立つけど、どうしようもない。受け入れなよ。", "C": "まだ失業を認めてないの？何もしないで座ってるのは時間の無駄。早く新しい仕事探しな。", "D": "現実を受け入れない。"}},
167: {"nativeDefinition": "Existing only in someone's imagination.", "japaneseMeaning": "気のせい、思い込み", "etymology": "all in one's head（全部頭の中）が実際には存在しないことを表す。", "examples": {"B": "マットがいじめてるって言う根拠ある？気のせいだと思う。彼は誰にでも厳しい。", "C": "ポールは根に持ってるの？全部気のせい？", "D": "誰かの想像の中。"}},
168: {"nativeDefinition": "Having very little time available.", "japaneseMeaning": "時間がない、急いでいる", "etymology": "pressed for time（時間に押されている）が時間不足を表す。", "examples": {"B": "時間がなくて、最後の問題は適当に答えた。正解だった。ラッキー。", "C": "時間がなくても、きちんとやらないと。手を抜く選択肢はない。", "D": "急いでいる。"}},
169: {"nativeDefinition": "The same as before; unchanged.", "japaneseMeaning": "いつもと同じ、変わらない", "etymology": "same old（いつもと同じ）が変化のない状態を表す。", "examples": {"B": "コールセンター2年目。もう少し皮が厚くなったと思ったけど、相変わらず敏感な人間。言葉は傷つく。", "C": "就活始めて2週間だけど、もう面接で同じ質問に答えるのにうんざり。", "D": "変わらない。"}},
170: {"nativeDefinition": "To remain calm and composed under pressure.", "japaneseMeaning": "冷静さを保つ、我慢する", "etymology": "keep it together（まとめて保つ）が感情を抑えることを表す。", "examples": {"B": "エブリンは最高。プレッシャーがかかっても冷静さを保てる。最高のプロジェクトリーダー。", "C": "卒業式で泣きすぎた。冷静さを保とうとしたけど、無理だった。", "D": "冷静でいる。"}},
171: {"nativeDefinition": "To manage to live or survive with limited resources.", "japaneseMeaning": "なんとかやっていく、生活する", "etymology": "get by（通り過ぎる）が最低限の生活を成り立たせることを表す。", "examples": {"B": "日本語学習に万能の方法はない。アニメ見まくって、日本でなんとかやっていけるレベルになった。", "C": "数年前はかろうじて生活してたけど、ビジネスが軌道に乗って自分の家も買えた。", "D": "なんとか生き延びる。"}},
172: {"nativeDefinition": "It's too complicated to explain briefly.", "japaneseMeaning": "長い話がある、話せば長い", "etymology": "it's a long story（長い話だ）が複雑さを示す定型表現。", "examples": {"B": "長い話だけど、要するに鍵、財布、スマホ全部一日でなくした。", "C": "長い話だけど、アーロンとは縁を切った。", "D": "とても複雑だ。"}},
173: {"nativeDefinition": "To have mixed feelings of love and dislike toward something.", "japaneseMeaning": "愛憎関係がある", "etymology": "love-hate relationship（愛憎関係）が相反する感情を表す。", "examples": {"B": "クロックスとは愛憎関係。すごく楽だけど、見た目はダサい。", "C": "deerじゃなくてdear。オートコレクトとは愛憎関係。", "D": "好きでも嫌いでもある。"}},
174: {"nativeDefinition": "Extremely thin.", "japaneseMeaning": "骨と皮だけ、やせこけている", "etymology": "skin and bones（皮と骨）が極端な痩せを表す。", "examples": {"B": "犬、骨と皮だけ。ちゃんと餌やってる？", "C": "もう少し太った方がいいよ。もう骨と皮だけ。", "D": "極端に痩せている。"}},
175: {"nativeDefinition": "Innovative; pioneering.", "japaneseMeaning": "画期的な、革新的な", "etymology": "groundbreaking（地面を破る）が新しい道を切り開くことを表す。", "examples": {"B": "この会社のことを画期的だと言うのは言い過ぎ。同じことをする会社はたくさんある。", "C": "当時FF7をプレイした記憶。グラフィックは当時画期的で、衝撃だった。", "D": "革新的な。"}},
176: {"nativeDefinition": "To have a natural talent for something.", "japaneseMeaning": "（〜の）才能がある、コツを掴んでいる", "etymology": "have a knack for（〜のコツがある）が生来の才能を表す。", "examples": {"B": "次のチームリーダーに名前を出すべき。人を指導する才能がある。", "C": "絵の才能はないから、なんでデザイナーになったのかわからない。", "D": "何かに生来の才能を持つ。"}},
177: {"nativeDefinition": "Based on first impressions; superficially.", "japaneseMeaning": "一見したところでは、表面的には", "etymology": "on the face of it（その表面で）が表面的な評価を表す。", "examples": {"B": "一見したところ、彼は時代遅れに見えるけど、ただ調子が悪いシーズンかも。", "C": "一見データは本物っぽいけど、深く調べると数字が合わない。", "D": "表面的に。"}},
178: {"nativeDefinition": "To some extent; partially.", "japaneseMeaning": "ある程度、部分的に", "etymology": "to a degree（程度まで）が部分的な同意や理解を表す。", "examples": {"B": "ある程度同意する。初デートで割り勘すべきじゃなかったかも。でもそれがうまくいかなかった理由じゃない。", "C": "税金の仕組みはある程度わかるけど、プロじゃない。質問はジェニーに。CPAだから。", "D": "ある程度。"}},
179: {"nativeDefinition": "In agreement with what you just said.", "japaneseMeaning": "あなたの言う通り、ご指摘のとおり", "etymology": "to your point（あなたのポイントに）が同意を示す表現。", "examples": {"B": "あなたのビジネスの素晴らしいところ、ご指摘のとおり、経済的に余裕のない学生にビジネス管理を学ぶ機会を与えてる。", "C": "ご指摘のとおり、データの正確性は疑わしい。誰も正当性を検証してないから、もっと批判的に調べる必要がある。", "D": "あなたが言ったことと一致して。"}},
180: {"nativeDefinition": "The kind of person someone finds attractive.", "japaneseMeaning": "（人の）好みのタイプ", "etymology": "one's type（自分のタイプ）が好みの異性のタイプを表す。", "examples": {"B": "すごく美人だけど、僕のタイプじゃない。ハイメンテナンスすぎ。", "C": "紹介しようか？あなたのタイプっていうほどじゃないけど、本当にいい人だよ。", "D": "誰かが魅力的だと思う人のタイプ。"}},
181: {"nativeDefinition": "To deliberately ignore or be unfriendly toward someone.", "japaneseMeaning": "（人を）冷たくあしらう、無視する", "etymology": "cold shoulder（冷たい肩）が冷たい扱いを表す。", "examples": {"B": "ウェイターが常連だと知らず冷たくあしらった。", "C": "最近子供たちに冷たくあしらわれてる気がする。理由がわからない。はっきり聞こう。", "D": "意図的に無視する。"}},
182: {"nativeDefinition": "To be unaware of current events or popular culture.", "japaneseMeaning": "世間知らず、情報通じゃない", "etymology": "live under a rock（岩の下に住む）が情報から隔離されていることを表す。", "examples": {"B": "カニエ・ウェストが誰かわからないの？岩の下に住んでる？", "C": "全部鵜呑みにしないで。これフェイクニュースで、数週間前に否定された。岩の下に住んでる？", "D": "時事に疎い。"}},
183: {"nativeDefinition": "Physical stores as opposed to online businesses.", "japaneseMeaning": "実店舗の、リアル店舗", "etymology": "brick-and-mortar（レンガとモルタル）が物理的な店舗を表す。", "examples": {"B": "オンライン売上は去年比66%増で、実店舗と肩を並べる。転換点に来たかも。", "C": "高額商品の分割払い、実店舗なら無利息で可能。", "D": "物理的な。"}},
184: {"nativeDefinition": "To contribute to or reinforce a stereotype or outcome.", "japaneseMeaning": "（偏見などを）助長する", "etymology": "play into（〜に加わる）が偏見を強めることを表す。", "examples": {"B": "ニックとの動画が、アメリカ人はスポットライトを独占したがるステレオタイプを助長してるのが心配。", "C": "みんなが僕はシャイだと思ってることを利用してる。", "D": "何かを強化する。"}},
185: {"nativeDefinition": "Wait; stop for a moment.", "japaneseMeaning": "ちょっと待って", "etymology": "hold up（持ち上げる）が「待て」を表す口語。", "examples": {"B": "ちょっと待って、そのアイデアもう一度説明して。よくわからなかった。", "C": "ちょっと待って、ラップトップがバグってる。再起動して配信再開する。ごめん、また連絡する。", "D": "待って。"}},
186: {"nativeDefinition": "Not typical of someone's character.", "japaneseMeaning": "（人の）性分じゃない", "etymology": "not in one's nature（性質にない）が本人らしくない行動を表す。", "examples": {"B": "仕事のことで怒るのは性分じゃない。昇進しなかったのは残念だけど、今は仕事を続ける。", "C": "小さなことで騒ぐことはない。性分じゃない。", "D": "誰かがするタイプのこと。"}},
187: {"nativeDefinition": "To work hard and diligently at something.", "japaneseMeaning": "（〜に）真剣に取り組む", "etymology": "apply oneself（自分を適用する）が努力を注ぐことを表す。", "examples": {"B": "彼はようやく勉強に真剣に取り組み始めたけど、手遅れかも。大学入試まであと2ヶ月。", "C": "人生で一番大事なのは、他人が望むことじゃなく、自分が好きなことに真剣に取り組むこと。", "D": "何かに一生懸命取り組む。"}},
188: {"nativeDefinition": "A method or formula that leads to success.", "japaneseMeaning": "成功の秘訣、成功のレシピ", "etymology": "recipe for success（成功のレシピ）が成功法を比喩的に表す。", "examples": {"B": "本を書くことに成功の秘訣なんてない。コツコツやるだけ。", "C": "このチームには成功のレシピがある。主力選手が不在でも勝つ方法を見つける。", "D": "成功する方法。"}},
189: {"nativeDefinition": "A short time after something begins.", "japaneseMeaning": "（始まってから）数分後", "etymology": "a few minutes into（〜に入って数分）が開始直後を表す。", "examples": {"B": "この本、始めて数分で退屈。", "C": "主人公が数分で死んだ。何これ？", "D": "何かが始まってから数分後。"}},
190: {"nativeDefinition": "To complete a task successfully.", "japaneseMeaning": "（仕事を）やり遂げる、完了する", "etymology": "get the job done（仕事を終える）が任務完了を表す。", "examples": {"B": "やり遂げるから、マイクロマネジメントしないで。", "C": "ヘレムはコーチすればやり遂げる。", "D": "タスクを完了する。"}},
191: {"nativeDefinition": "An unknown or unimportant person.", "japaneseMeaning": "無名の人、誰でもない人", "etymology": "nobody（誰でもない人）が無名・取るに足らない人を表す。", "examples": {"B": "トロイが今TVに出まくってるなんて信じられない。3週間前会った時は無名だった。", "C": "バーテンダーが俺たちを無名扱いした。服装のせいかな。次はスーツ着て行こう。", "D": "無名または取るに足らない人。"}},
192: {"nativeDefinition": "Not feeling completely well or healthy.", "japaneseMeaning": "体調が万全じゃない", "etymology": "not feeling a hundred percent（100%の気分じゃない）が体調不良を表す。", "examples": {"B": "体調万全じゃないなら、数日休んだ方がいいよ。", "C": "ここ数日万全じゃないけど、明日には大丈夫なはず。触らないで。", "D": "体調が良くない。"}},
193: {"nativeDefinition": "To influence someone through exposure.", "japaneseMeaning": "（人に）影響を与える", "etymology": "rub off on（擦り付ける）が影響が及ぶことを表す。", "examples": {"B": "このYouTuberの影響で毎日勉強するようになった。最初は嫌だったけど、今は楽しい。", "C": "お前に影響与え始めたのか。いつからロック好きになった？", "D": "誰かに影響を与える。"}},
194: {"nativeDefinition": "To reconsider carefully before acting.", "japaneseMeaning": "よく考える、再考する", "etymology": "think twice（二回考える）が慎重に検討することを表す。", "examples": {"B": "SNSに個人情報を投稿するのは卑劣。こういうの投稿する前によく考えな。", "C": "このサイトから買う前によく考えて。すごく怪しい。", "D": "立ち止まって再考する。"}},
195: {"nativeDefinition": "I didn't know that; that's new information to me.", "japaneseMeaning": "初耳だ、知らなかった", "etymology": "that's news to me（それは私にとってニュースだ）が初耳を表す。", "examples": {"B": "新しい彼氏いるの？初耳。さっき別れたばかりじゃん。", "C": "中国語話せるの？初耳だ。", "D": "知らなかった。"}},
196: {"nativeDefinition": "I promise not to reveal a secret.", "japaneseMeaning": "口外しない、秘密は守る", "etymology": "my lips are sealed（唇は封じられている）が秘密保持を表す。", "examples": {"B": "心配しないで、今日一日Netflix見てたことは誰にも言わない。口は堅いから。", "C": "何考えてるの？言ってよ。口外しない。", "D": "秘密を誰にも言わないと約束する。"}},
197: {"nativeDefinition": "Something that seems bad but turns out to be good.", "japaneseMeaning": "不幸中の幸い、逆に良かったこと", "etymology": "blessing in disguise（変装した祝福）が一見不幸な出来事の好結果を表す。", "examples": {"B": "片思いにghostされたのは辛いけど、不幸中の幸いだと思う。時間を無駄にしなくていい。", "C": "サイズが売り切れで買えなかったのは不幸中の幸い。お金使わなくて済んだ。", "D": "実はポジティブなこと。"}},
198: {"nativeDefinition": "Expressing nostalgia for a happy past time.", "japaneseMeaning": "あの頃が良かった、懐かしい", "etymology": "those were the days（あれがあの日々だった）が懐かしさを表す。", "examples": {"B": "マクドナルドのハンバーガーが6ドルだった頃、あの頃が良かった。", "C": "子供の頃、父と一緒にドラゴンボール見てた。あの頃が良かった。", "D": "あんなに素晴らしい時代だった。"}},
199: {"nativeDefinition": "Speaking one's thoughts aloud without filtering.", "japaneseMeaning": "独り言、考えを声に出す", "etymology": "think out loud（声に出して考える）が独り言を表す。", "examples": {"B": "動画が嫌なら見なければいいじゃん。わかんないけど、独り言。", "C": "独り言だけど、香水のCMって嗅げないのに意味ある？", "D": "考えを声に出すだけ。"}},
200: {"nativeDefinition": "In the future; later on.", "japaneseMeaning": "将来的に、そのうち", "etymology": "down the track（線路の先）がオーストラリア英語で将来を表す。", "examples": {"B": "今は子供欲しくないけど、将来的には家族を持ちたい。", "C": "正社員を辞めてスタートアップに集中することにした。将来的に報われるといい。", "D": "将来。"}},
201: {"nativeDefinition": "To schedule something tentatively.", "japaneseMeaning": "（仮で）予定を入れる", "etymology": "pencil in（鉛筆で書く）が仮予約を表す。", "examples": {"B": "土曜ランチ仮で入れてたけど、来週にずらせる？", "C": "行けるかまだわからないけど、とりあえず仮で入れといて。スケジュール確定したら連絡する。", "D": "仮予約する。"}},
202: {"nativeDefinition": "To continue through difficulty with determination.", "japaneseMeaning": "（困難を）乗り越えて進む", "etymology": "push through（押し通す）が困難を力ずくで乗り越えることを表す。", "examples": {"B": "今つらい時期だけど、あと数週間乗り越えれば良くなる。", "C": "明確な目標があれば、障害を乗り越えて進める。", "D": "何かを通過して進む。"}},
203: {"nativeDefinition": "To put yourself in social situations despite risk of rejection.", "japaneseMeaning": "（人前に）飛び出す、積極的に行動する", "etymology": "put oneself out there（自分を外に出す）が社交的に行動することを表す。", "examples": {"B": "人前に飛び出すのを恐れないで。拒絶を恐れて生きたら、機会を逃し続ける。", "C": "人付き合いが上手くなりたいなら、コンフォートゾーンから出て積極的に行動しないと。", "D": "もっと社交的になる。"}},
204: {"nativeDefinition": "Within reasonable limits; not excessively.", "japaneseMeaning": "ほどほどに、節度を持って", "etymology": "in moderation（節度を持って）が適度な範囲を表す。", "examples": {"B": "ほどほどなら備蓄も問題ないけど、トイレットペーパーこれは多すぎ。城でも建てる？", "C": "Netflix見すぎをやめないと。いつも時間を忘れる。何事もほどほどに。", "D": "合理的な範囲内で。"}},
205: {"nativeDefinition": "To have a lot of available time.", "japaneseMeaning": "時間はいくらでもある", "etymology": "all the time in the world（世界中の時間）が時間に余裕があることを表す。", "examples": {"B": "人は時間はいくらでもあると思いがちだけど、人生は短い。", "C": "夏休みだから時間はいくらでもある。何すればいいかわからない。", "D": "たくさんの時間がある。"}},
206: {"nativeDefinition": "Finally and completely, so it won't happen again.", "japaneseMeaning": "今度こそ完全に、最後に", "etymology": "once and for all（一度で永遠に）が完全な解決を表す。", "examples": {"B": "Facebookを今度こそ完全にやめた。年寄りが若者を説教するのにうんざり。", "C": "今度こそ決着をつけよう。ビートルズとブラック・アイド・ピース、どっちが史上最高のバンド？", "D": "完全に最終的に。"}},
207: {"nativeDefinition": "To get into a vehicle; to join someone.", "japaneseMeaning": "（車に）乗る", "etymology": "hop on（飛び乗る）が車などに乗る口語表現。", "examples": {"B": "乗せて。30分以内にどこか行くけど、途中で降ろしてあげる。", "C": "今モールに向かってる。乗る？", "D": "乗る。"}},
208: {"nativeDefinition": "To remain in someone's memory for a long time.", "japaneseMeaning": "（記憶に）残る", "etymology": "stay with（一緒にいる）が記憶に残ることを表す。", "examples": {"B": "子供時代の経験は大人になっても残る。親は言葉に気をつけないと。", "C": "カエル食べてる写真、本当に気持ち悪かった。一生残りそう。", "D": "誰かの記憶に残る。"}},
209: {"nativeDefinition": "To use the last remaining poor-quality options.", "japaneseMeaning": "（選択肢が）底をつく、しわ寄せが来る", "etymology": "scrape the bottom of the barrel（樽の底をこする）が最悪の選択肢に迫ることを表す。", "examples": {"B": "待って、1年前に似たような番組なかった？アイデアの底をついてる。", "C": "有名人を候補にするなんて、本当に選択肢の底をついてる。", "D": "良い選択肢がなくなる。"}},
210: {"nativeDefinition": "To start a conversation or relationship.", "japaneseMeaning": "（会話などを）始める", "etymology": "strike up（打ち始める）が会話や関係を始めることを表す。", "examples": {"B": "彼女と会話を始めたいけど、緊張しすぎる。", "C": "兄とすぐに仲良くなった。みんな変人だと思ってるけど、僕も変？", "D": "何かを始める。"}},
211: {"nativeDefinition": "No longer available as an option.", "japaneseMeaning": "（選択肢から）外れた、もう無理", "etymology": "off the table（テーブルから外れた）が選択肢から除外されたことを表す。", "examples": {"B": "ごめん、オファーはもう無効。時間がない。", "C": "今はキャリアに集中したいから、結婚は選択肢から外れた。", "D": "選択肢ではない。"}},
212: {"nativeDefinition": "To research or study something by reading.", "japaneseMeaning": "（〜について）調べる、読んで学ぶ", "etymology": "read up on（読んで調べる）が文献等で調査することを表す。", "examples": {"B": "ロシア史を教えたことないけど、数日調べれば簡単だよ。", "C": "来週面接する会社について調べてる。", "D": "何かを調査する。"}},
213: {"nativeDefinition": "A list of things to do before one dies.", "japaneseMeaning": "バケットリスト、やりたいことリスト", "etymology": "bucket list（バケツリスト）が死ぬ前にやりたいことリストを表す。", "examples": {"B": "ビヨンセのコンサートはバケットリストのトップ。チケット取るの超難しいけど。", "C": "現時点でバケットリストで未達成なのは宇宙旅行だけ。", "D": "人生で達成したいことのリスト。"}},
214: {"nativeDefinition": "To trick or deceive someone into doing something.", "japaneseMeaning": "（人を）だます、騙す", "etymology": "con（confidence trick＝詐欺）がだますことを表す。", "examples": {"B": "スイス銀行口座に全財産移すよう騙されて、彼は消えた。どれだけバカ？", "C": "この男、人から金を騙し取ったって聞いた。証拠はないけど、噂が多い。噂に火はないけど煙はある。", "D": "だまして何かさせる。"}},
215: {"nativeDefinition": "To think very highly of someone.", "japaneseMeaning": "（人を）とても高く評価する", "etymology": "think the world of（世界ほど思う）が最高の評価を表す。", "examples": {"B": "ジョンは親友だから、彼のこと最高に思ってる。", "C": "お父さん、あなたのこと最高に思ってる。豚が空を飛ぶなんて言ったのは本心じゃない。", "D": "誰かを高く評価する。"}},
216: {"nativeDefinition": "The most talented and intelligent people.", "japaneseMeaning": "エリート、優秀な人材", "etymology": "best and brightest（最高で最も明るい）が優秀な人材を表す。", "examples": {"B": "今夜シリコンバレーのエリートと夕食。緊張する。", "C": "うちの会社は基準が高く、エリートだけ採用する。", "D": "非常に賢い人々。"}},
217: {"nativeDefinition": "The newest and best version of something.", "japaneseMeaning": "最新かつ最高の", "etymology": "latest and greatest（最新で最高）が最新モデルを表す。", "examples": {"B": "最新かつ最高の情報はウェブサイトをチェックして。", "C": "新iPhoneが出るたびに最新版買う意味ある？そんなに違わない。", "D": "最新で最高の。"}},
218: {"nativeDefinition": "Occasionally; in various places.", "japaneseMeaning": "たまに、あちこちで", "etymology": "here and there（あちこち）が散発的にを表す。", "examples": {"B": "休暇中もたまに運動するようにしてる。でもあまりやる気にならない。", "C": "モデルは副業で、たまに小遣いになるけど、ずっとはできない。", "D": "時々。"}},
219: {"nativeDefinition": "Having learned a skill without formal education.", "japaneseMeaning": "独学の", "etymology": "self-taught（自己教師）が独学を表す。", "examples": {"B": "本当に独学のピアニストは稀。", "C": "独学のアプリ開発者だけど、普通のこと。無料オンラインコースでたくさん学べる。", "D": "正式な教育なしでスキルを身につけた。"}},
220: {"nativeDefinition": "To express one's opinion openly.", "japaneseMeaning": "意見を述べる", "etymology": "voice one's opinion（意見に声を与える）が意見表明を表す。", "examples": {"B": "意見を述べることに反対してるわけじゃない。もっと聞いてほしいだけ。", "C": "SNSで意見を述べるのは控えめにしてる。バカなこと言って自分の首絞めたくない。", "D": "自分の立場を表明する。"}},
221: {"nativeDefinition": "To improve or increase; to resume.", "japaneseMeaning": "（調子が）上がる、再開する", "etymology": "pick up（拾う）が回復・増加・再開を表す。", "examples": {"B": "失礼、来週また再開するから、今のうちに休む。またね。", "C": "なぜかわからないけど、ここ数ヶ月業績が上がってる。", "D": "増加または改善する。"}},
222: {"nativeDefinition": "An opinion from another expert or person.", "japaneseMeaning": "セカンドオピニオン、他の意見", "etymology": "second opinion（第二の意見）が別の専門家の意見を表す。", "examples": {"B": "オレンジはビタミンC豊富で肌に良いと思うけど、セカンドオピニオン歓迎。", "C": "アメリカ人はsurely使わないなんて同意しない。聞いたことある。セカンドオピニオン必要。", "D": "他の人からのアドバイス。"}},
223: {"nativeDefinition": "To gradually become quieter or less intense.", "japaneseMeaning": "（盛り上がりが）収まる、静まる", "etymology": "die down（静かに消える）が勢いが衰えることを表す。", "examples": {"B": "ツイートの通知、やっと収まった。数日で1万いいね超えた。", "C": "このレストラン、先週オープン以来すごい盛り上がり。あの行列見て。落ち着くまで待とう。", "D": "静かになる。"}},
224: {"nativeDefinition": "Emotionally upset, especially by something offensive.", "japaneseMeaning": "キレる、感情的になる", "etymology": "triggered（引き金を引かれた）がSNSスラングで強い感情反応を表す。", "examples": {"B": "陰口叩かれてるって聞いて本当にキレた。今回は許す。", "C": "ジェームズが体重をからかった時、彼女かなりキレてた。卑劣な攻撃だった。", "D": "動揺する。"}},
225: {"nativeDefinition": "To behave very politely and properly.", "japaneseMeaning": "良い子にする、最善の行動をする", "etymology": "on one's best behavior（最高の行動で）が礼儀正しく振る舞うことを表す。", "examples": {"B": "何度言えば良い子にするの？高級レストランで大声出しちゃダメなの、もうわかってるでしょ。", "C": "ランチ中、子供たちは良い子にしてた。", "D": "とても良く振る舞う。"}},
226: {"nativeDefinition": "To be familiar with the usual procedure.", "japaneseMeaning": "やり方はわかってる、お決まり", "etymology": "know the drill（手順を知っている）が慣れた流れを表す。", "examples": {"B": "さあ子供たち、寝る時間。やり方わかってるでしょ。ベッド作って、スマホ消して、電気消して。", "C": "もうやり方わかってるでしょ。食事中は肘をテーブルにつけない。", "D": "何をすべきか熟知している。"}},
227: {"nativeDefinition": "To have something handled or taken care of.", "japaneseMeaning": "（〜は）任せて、カバーする", "etymology": "have covered（カバーされている）が対応済みを表す。", "examples": {"B": "父さん、母の日は心配しないで。任せて。", "C": "昨日のウェビナー逃した？カバーするよ。YouTubeで見れる。", "D": "何かの面倒を見る。"}},
228: {"nativeDefinition": "To look back a few years in the past.", "japaneseMeaning": "数年前に遡ると", "etymology": "go back a few years（数年前に戻る）が過去を振り返る表現。", "examples": {"B": "数年前、日本に来たばかりの頃に遡ると、簡単なフレーズしか知らなかった。長い道のり。", "C": "数年前に遡ると、Siriが何か知ってる人はほとんどいなかった。バーチャルアシスタントは大進歩。", "D": "数年前のこと。"}},
229: {"nativeDefinition": "A person who hides nothing; easy to read.", "japaneseMeaning": "オープンブック、読みやすい人", "etymology": "open book（開いた本）が隠し事のない人を表す。", "examples": {"B": "僕はオープンブック。顔を見れば何考えてるかわかる。", "C": "僕の人生はオープンブック。Instagramに全部投稿してる。", "D": "秘密のない人や物。"}},
230: {"nativeDefinition": "What's going on with someone or something?", "japaneseMeaning": "どうしたの、何なの", "etymology": "what's with（〜はどうなってる）が原因や状態を問う表現。", "examples": {"B": "ヒゲどうしたの？大人っぽく見せようとしてる？", "C": "ベン、今日どうしたの？いつも陽気なのに、今日は曇り。", "D": "何かどうなってる？"}},
231: {"nativeDefinition": "Unreliable; flaky (often about people or connections).", "japaneseMeaning": "当てにならない、フレーク", "etymology": "flaky（剥がれやすい）が約束を守らない人を表す。", "examples": {"B": "ネットがすごく不安定。ラグが酷い。", "C": "約束の時間に来ない。本当に当てにならない。", "D": "不安定または信頼できない。"}},
232: {"nativeDefinition": "To provide an experience that teaches someone a lesson.", "japaneseMeaning": "（人に）教訓を与える", "etymology": "teach a lesson（教訓を教える）が経験を通じた学びを表す。", "examples": {"B": "蚊に刺された。キャンプに虫除け持ってくるの忘れた。良い教訓だった。", "C": "失敗から貴重な教訓を学ぶ。", "D": "学ぶ機会を与える。"}},
233: {"nativeDefinition": "A particular field or area of activity.", "japaneseMeaning": "分野、領域", "etymology": "arena（闘技場）が比喩的に活動分野を表す。", "examples": {"B": "アダムと同じ会社だけど、別の分野だからあまり話さない。", "C": "数学の理解は多くの分野で役立つ。", "D": "分野。"}},
234: {"nativeDefinition": "To hear something said frequently.", "japaneseMeaning": "（〜と）よく言われる", "etymology": "get that a lot（それをよく聞く）が頻繁に言われることを表す。", "examples": {"B": "ハンサムだと思う？よく言われるよ。", "C": "目の色きれい。よく言われる？", "D": "よく言われる。"}},
235: {"nativeDefinition": "In small amounts; tolerable only briefly.", "japaneseMeaning": "少量なら、少しなら", "etymology": "in small doses（小さな量で）が少量なら我慢できることを表す。", "examples": {"B": "新しい仕事への exposure は少量なら良いけど、頻繁だとストレス。", "C": "毎日ドヤ顔自撮りをInstagramに上げる。少量なら我慢できるけど、これは多すぎ。", "D": "少量で。"}},
236: {"nativeDefinition": "To be in a good, successful situation.", "japaneseMeaning": "うまくいってる、良い関係・状況", "etymology": "have a good thing going（良いことが進行中）が好調な状態を表す。", "examples": {"B": "本当に別れるの？うまくいってるじゃん。バカな口論で台無しにするのはもったいない。", "C": "この会社ではうまくいってるから、しばらく居続けよう。", "D": "物事が順調な状況にある。"}},
237: {"nativeDefinition": "That would change the situation or my opinion.", "japaneseMeaning": "それは別の話、状況が変わる", "etymology": "that's a different story（それは別の話）が条件次第で変わることを表す。", "examples": {"B": "普通、裏で金を渡して違法なことするのは正しくない。でも命を救うなら、それは別の話。", "C": "犬は大好き。でもチキンナゲット食べられたら、それは別の話。", "D": "意見が変わる。"}},
238: {"nativeDefinition": "To briefly think of something.", "japaneseMeaning": "（頭に）よぎる、思い浮かぶ", "etymology": "cross one's mind（心を横切る）が一瞬思い浮かぶことを表す。", "examples": {"B": "数年前まで、この単語リストを本に出版しようとは思わなかった。", "C": "スペイン語を始めようと思ったけど、今はイタリア語に集中した方がいい。", "D": "誰かの心に浮かぶ。"}},
239: {"nativeDefinition": "To require some improvement.", "japaneseMeaning": "（〜に）少し手直しが必要", "etymology": "need a bit of work（少しの仕事が必要）が改善の余地を表す。", "examples": {"B": "新しい家の庭、まだ少し手直しが必要。12月までに終わらせてクリスマスパーティーしたい。", "C": "ウェブデザインのスキル、少し手直しが必要。ケイトにブランチしよう。プロだから。", "D": "改善が必要。"}},
240: {"nativeDefinition": "To lose energy or motivation.", "japaneseMeaning": "（勢いが）尽きる、疲れる", "etymology": "run out of steam（蒸気が尽きる）がエネルギー切れを表す。", "examples": {"B": "この経済学者、中国経済はすぐ勢いが尽きると言うけど、わからない。", "C": "本の大部分は書いたけど、勢いが尽きてきた。表紙デザインはクリスマス後に回そう。", "D": "動きが止まる。"}},
241: {"nativeDefinition": "To change one's opinion or attitude.", "japaneseMeaning": "考えを変える、口を改める", "etymology": "change one's tune（調子を変える）が考えの転換を表す。", "examples": {"B": "牛乳嫌いでしょ？これ試して。考え変わるよ。", "C": "なんで子供が嫌いなの？子供持てば考え変わるよ。", "D": "意見を変える。"}},
242: {"nativeDefinition": "To be important or influential.", "japaneseMeaning": "（発言などが）重みがある、影響力がある", "etymology": "carry weight（重みを持つ）が影響力を表す。", "examples": {"B": "推薦状を履歴書に添付して。評価プロセスで重みがある。", "C": "インフルエンサーとして発言すべきじゃなかった。言葉の重みを自覚すべきだった。", "D": "重要または影響力がある。"}},
243: {"nativeDefinition": "I am certain that something is true.", "japaneseMeaning": "確信している", "etymology": "I'm convinced（説得された＝確信している）が強い確信を表す。", "examples": {"B": "新コーチ雇うと原点回帰する。カルロの下で順調に進んでる。判断するには早すぎる。", "C": "スティーブ・ジョブズが生きてれば、もっと革新的なiPhoneを作ったと確信してる。", "D": "確信している。"}},
244: {"nativeDefinition": "Greatest Of All Time.", "japaneseMeaning": "史上最高（GOAT）", "etymology": "GOAT（Greatest Of All Time＝史上最高）の頭字語。", "examples": {"B": "間違いなく、ロナウドは偉大な選手だけど、真のGOATはペレ。", "C": "ロバート・デ・ニーロはGOAT。良い映画たくさん、人柄も最高。", "D": "史上最高。"}},
245: {"nativeDefinition": "In an unstable or uncertain situation.", "japaneseMeaning": "不安定な状況、危うい立場", "etymology": "on shaky ground（揺れる地面の上）が不安定な状態を表す。", "examples": {"B": "YouTubeやInstagramに依存するビジネスは不安定な立場にいる。", "C": "別れても不思議じゃない。15年付き合って結婚してないのは関係が危ういサイン。", "D": "不安定な。"}},
246: {"nativeDefinition": "With sincere, genuine feeling.", "japaneseMeaning": "心から、本心から", "etymology": "from the heart（心から）が誠実な感情を表す。", "examples": {"B": "心からの感動的なスピーチだった。録画しなかったことを後悔してる。", "C": "心からありがとう。一日を良くしてくれた。", "D": "誠実な気持ちで。"}},
247: {"nativeDefinition": "To understand the mood or atmosphere of a situation.", "japaneseMeaning": "空気を読む", "etymology": "read the room（部屋を読む）が場の雰囲気を理解することを表す。", "examples": {"B": "空気読んで。みんな残業で必死。スペイン旅行の話なんて誰も聞きたくない。", "C": "ジャックは面白いけど、たまに空気読んでほしい。", "D": "雰囲気を理解する。"}},
248: {"nativeDefinition": "A joke that is stereotypically told by middle-aged men.", "japaneseMeaning": "お父さんギャグ、ダジャレ", "etymology": "dad joke（父親のジョーク）が中年男性の寒いジョークを表す。", "examples": {"B": "見方によっては、ピートのお父さんギャグは実は面白い。全員にはウケないけど。", "C": "父がお父さんギャグ始めるたび、母が遮る。", "D": "中年男性のジョーク。"}},
249: {"nativeDefinition": "Expressing disbelief (also: leave!).", "japaneseMeaning": "マジか、うそでしょ", "etymology": "get out of here（ここから出て行け）が驚きの表現にも使われる。", "examples": {"B": "うそでしょ。一日で100万ドル稼いだの？", "C": "大統領が直接連絡してきたの？うそでしょ。", "D": "信じられない。"}},
250: {"nativeDefinition": "To be said unintentionally.", "japaneseMeaning": "（言葉が）つい口から出る", "etymology": "slip out（滑り出る）が意図せず言ってしまうことを表す。", "examples": {"B": "くしゃみの時にチワワみたいに聞こえるなんて言うつもりなかった。つい口から出た。", "C": "彼女に愛してるって言っちゃった。ちょっと飲んでたから、つい。", "D": "意図せず言われる。"}},
251: {"nativeDefinition": "At the same level as something else.", "japaneseMeaning": "（〜と）同等の、同レベルの", "etymology": "on par with（〜と同じ水準で）が同等を表す。", "examples": {"B": "この新しい検索エンジン、結果はGoogleと同等。Googleアシスタントが邪魔しない分、快適。", "C": "ここ数年ボイストレーニングしてるけど、プロ歌手にはまだ及ばない。", "D": "何かと同じレベルで。"}},
252: {"nativeDefinition": "To push through difficulty with strong effort.", "japaneseMeaning": "（困難を）力強く乗り切る", "etymology": "power through（力で通す）が強い意志で進むことを表す。", "examples": {"B": "あのエナジードリンク、命の恩人。寝ずに一日乗り切れた。", "C": "やる気があるうちに力強く乗り切って終わらせる。鉄は熱いうちに打て。", "D": "力強く進む。"}},
253: {"nativeDefinition": "To provide someone with something, often through connections.", "japaneseMeaning": "（人に〜を）用意してあげる、紹介する", "etymology": "hook up（つなぐ）が人と物を結びつけるスラング。", "examples": {"B": "高給の仕事用意してくれる人いない？経験ゼロだけど、学ぶ意欲はある。", "C": "コネ使えばフロントローのチケット用意できるけど、高いよ。いい？", "D": "誰かに何かを手配する。"}},
254: {"nativeDefinition": "To reach the highest point of ability or popularity.", "japaneseMeaning": "（能力の）ピークに達する", "etymology": "peak（頂点）が最高潮に達することを表す。", "examples": {"B": "彼女、とっくにピーク過ぎ。新曲なんて何年も出てない。", "C": "プロサッカー選手は25〜27歳でピーク。若いね。", "D": "可能な限り最高レベルに達する。"}},
255: {"nativeDefinition": "To inform on someone; a person who informs.", "japaneseMeaning": "密告する、裏切り者", "etymology": "snitch（密告者）が内部告発を表すスラング。", "examples": {"B": "友達が宿題コピーしたことを密告した。裏切られた気分。", "C": "マークが密告者だと思う？誰か上司にオンラインショッピングしてたって言った。君じゃないよね？", "D": "密告者。"}},
256: {"nativeDefinition": "From a different perspective or viewpoint.", "japaneseMeaning": "別の視点から、異なるレンズで", "etymology": "through a different lens（異なるレンズを通して）が視点の転換を表す。", "examples": {"B": "外国語を学ぶだけで賢くなるかはわからないけど、別の視点で世界を見られる。", "C": "別の視点で問題を見たら、核心にたどり着けた。", "D": "異なる視点から。"}},
257: {"nativeDefinition": "A temporary lapse in memory or thinking.", "japaneseMeaning": "頭が真っ白、一時的な記憶障害", "etymology": "brain fart（脳のおなら）が一時的な思考停止を表すスラング。", "examples": {"B": "やばい、頭が真っ白。ディズニーの有名なネズミの名前何だっけ？", "C": "ステージで頭が真っ白になって恥ずかしいのが嫌。原稿読むことにした。", "D": "一時的な記憶障害。"}},
258: {"nativeDefinition": "To have a very kind and generous nature.", "japaneseMeaning": "心の優しい人、金の心を持つ", "etymology": "heart of gold（金の心）が非常に優しい本性を表す。", "examples": {"B": "彼女は彼が心の優しい人だと言うけど、実際に誰かに親切にしてるとこ見たことない。", "C": "ライアン、本当に心優しい人だよね。いつも他人のことを考えてる。", "D": "寛大で優しい性質を持つ。"}},
259: {"nativeDefinition": "To claim something for oneself before others.", "japaneseMeaning": "（〜を）取り置きする、先取りする", "etymology": "call dibs（取り置きを宣言する）が先取り権を主張するスラング。", "examples": {"B": "最後のピザの取り置き宣言した。午後のトレーニングにエネルギー必要だから。", "C": "うちの犬、いつも助手席の取り置き宣言する。僕は後部座席。", "D": "何かの権利を主張する。"}},
260: {"nativeDefinition": "To doubt or question something after the fact.", "japaneseMeaning": "（〜を）後から疑う、やり直す", "etymology": "second-guess（二回推測する）が後から判断を疑うことを表す。", "examples": {"B": "いつも自分の決断を後から疑う。もっと自信が欲しい。", "C": "fortyのスペル、Uがないのをいつも後から疑う。fourと同じだから。", "D": "何かを疑う。"}},
261: {"nativeDefinition": "In someone's opinion or judgment.", "japaneseMeaning": "（人に）とって、（人の）目から見れば", "etymology": "in one's eyes（誰かの目に）がその人の評価基準を表す。", "examples": {"B": "マイケル・ジョーダンは僕にとって史上最高の選手。", "C": "彼女は僕の目から見れば常に完璧。", "D": "誰かの意見では。"}},
262: {"nativeDefinition": "An additional benefit that makes something even better.", "japaneseMeaning": "さらに良いもの、錦上花添", "etymology": "icing on the cake（ケーキのトッピング）が上乗せの良さを表す。", "examples": {"B": "カフェのコーヒーは最高で、リラックスした雰囲気はさらに良かった。", "C": "修士号は就職の足がかりになる？それとも錦上花添？", "D": "状況をさらに良くするもの。"}},
263: {"nativeDefinition": "To make every possible effort to help someone.", "japaneseMeaning": "（人のために）全力を尽くす", "etymology": "bend over backwards（後ろに反る）が最大限の努力を表す。", "examples": {"B": "彼女に完全に従ってる。彼女が頼むことにはいつも全力尽くすでしょ？", "C": "全力尽くして助けたのに、お礼も言われないの嫌。", "D": "あらゆる努力をする。"}},
264: {"nativeDefinition": "Do whatever you want; it's your choice.", "japaneseMeaning": "好きにすればいい、あなたの自由", "etymology": "you do you（あなたはあなたをする）が他人の選択を尊重するスラング。", "examples": {"B": "この高級フレンチレストランでラップトップ使うの？変な目で見られるけど、好きにすればいいよ。", "C": "チーズもっと足すの？十分だと思うけど、好きにすれば。", "D": "好きなことをする。"}},
265: {"nativeDefinition": "To watch carefully; stay alert.", "japaneseMeaning": "目を光らせる、注意して見ておく", "etymology": "keep one's eyes peeled（目を剥く）が警戒することを表す。", "examples": {"B": "新エピソード出るから、目を光らせておく。", "C": "仕事探してるんだ。目を光らせておくね。", "D": "注意する！"}},
266: {"nativeDefinition": "To wash up and make oneself look cleaner.", "japaneseMeaning": "身なりを整える、さっぱりする", "etymology": "freshen up（新鮮にする）が身だしなみを整えることを表す。", "examples": {"B": "夕食前に身なり整える時間ちょうだい。", "C": "ワークアウト終わった。さっぱりして連絡する。", "D": "身を清める。"}},
267: {"nativeDefinition": "Almost remembered but not quite.", "japaneseMeaning": "喉まで出かかっている", "etymology": "on the tip of one's tongue（舌の先）が記憶の寸前を表す。", "examples": {"B": "ルーシーの名字、喉まで出かかってる。Aで始まるのは確かだけど、思い出せない。", "C": "あ、この人知ってる。名前何だっけ？喉まで出かかってる。", "D": "もう少しで思い出せる。"}},
268: {"nativeDefinition": "To notice oneself doing something unconsciously.", "japaneseMeaning": "（自分が〜してるのに）気づく", "etymology": "catch oneself doing（自分が〜するのを捕まえる）が無意識の行動に気づくことを表す。", "examples": {"B": "運転中にボーッとしてる自分に気づくことが多い。まだ生きてるの不思議。", "C": "緊張やストレスの時、口の中側を噛んでる自分に気づく。なんでだろう。", "D": "自分が〜していることに気づく。"}},
269: {"nativeDefinition": "To behave as badly as someone else.", "japaneseMeaning": "（人と）同レベルの低い行動をする", "etymology": "sink to one's level（相手のレベルに沈む）が相手に合わせて堕落することを表す。", "examples": {"B": "お前のレベルに下がってネットでケンカするつもりはない。お前誰？僕には人生がある。", "C": "仕返しに時間を無駄にしたくない。相手のレベルに下がりたくない。", "D": "相手と同じ低い行動をする。"}},
270: {"nativeDefinition": "To impress or amaze someone greatly.", "japaneseMeaning": "（人を）圧倒する、驚かせる", "etymology": "blow away（吹き飛ばす）が強い感動を表す。", "examples": {"B": "この超リアルな絵、圧倒された。一見写真だけど、鉛筆画。", "C": "トイレ掃除から社長になった。圧倒される。", "D": "誰かを驚かせる。"}},
271: {"nativeDefinition": "Avoiding language that could offend marginalized groups.", "japaneseMeaning": "ポリティカルコレクトな", "etymology": "politically correct（政治的に正しい）が差別的表現を避けること。", "examples": {"B": "最近ポリコレしすぎだと思う。みんないつも他人の言葉を監視してる。", "C": "日本人をJapsって呼ぶの、ポリコレじゃない。", "D": "攻撃的でない。"}},
272: {"nativeDefinition": "Consecutively; in a row.", "japaneseMeaning": "連続で、ずっと", "etymology": "straight（まっすぐ）が連続を表す口語用法。", "examples": {"B": "2、3週間は何も食べずにいける自信ある。", "C": "20日連続で働いてる。週末は髪を下ろしたい。", "D": "連続して。"}},
273: {"nativeDefinition": "Fortunately, something happened.", "japaneseMeaning": "（〜して）良かった、幸い", "etymology": "good thing（良いこと）が幸運な結果を表す。", "examples": {"B": "昨夜疲れすぎてアラームセット忘れた。良かった、早起きした。", "C": "一緒にいてくれて良かった。あの怖い男に一人では立ち向かえなかった。", "D": "幸い、何かがそうする。"}},
274: {"nativeDefinition": "Simplicity is better than excess.", "japaneseMeaning": "少ない方がいい、シンプルイズベスト", "etymology": "less is more（少ないほど多い）がミニマリズムの格言。", "examples": {"B": "校長はいつも長話。要点を言えよ。少ない方がいいってわかってない。", "C": "少ない方がいい believer。だからアパートにはソファとテーブルだけ。", "D": "シンプルな方が良い。"}},
275: {"nativeDefinition": "Completely empty and deserted.", "japaneseMeaning": "ゴーストタウンのように、誰もいない", "etymology": "ghost town（幽霊町）が無人の状態を表す。", "examples": {"B": "今朝のコストコ、ゴーストタウンみたい。天気のせいかも。", "C": "クリスマス後、観光客が去るとこのレストランはゴーストタウンになる。", "D": "誰もいない。"}},
}
